**Updated component structure**:

```tsx
"use client";

import { useActiveOrg } from "@repo/app-trpc/hooks";
import type { SearchMode } from "@repo/app-validation";
import type { PromptInputMessage } from "@repo/ui/components/ai-elements/prompt-input";
import { ScrollArea } from "@repo/ui/components/ui/scroll-area";
import { Separator } from "@repo/ui/components/ui/separator";
import { Skeleton } from "@repo/ui/components/ui/skeleton";
import { parseError } from "@vendor/observability/error/next";
import { keepPreviousData, useQuery } from "@tanstack/react-query";
import { useEffect, useMemo, useState } from "react";
import { createApiClient } from "~/lib/api-client";
import { dateRangeFromPreset } from "./search-constants";
import { SearchFilters } from "./search-filters";
import { SearchPromptInput } from "./search-prompt-input";
import { SearchResultsPanel } from "./search-results-panel";
import { useOrgSearchParams } from "./use-org-search-params";

interface OrgSearchProps {
  initialQuery: string;
}

export function OrgSearch({ initialQuery }: OrgSearchProps) {
  const activeOrg = useActiveOrg();
  const clerkOrgId = activeOrg?.id ?? "";

  // Typed oRPC client scoped to the active org
  const client = useMemo(() => createApiClient(clerkOrgId), [clerkOrgId]);

  // URL-persisted state via nuqs (unchanged)
  const {
    query, setQuery,
    mode, setMode,
    sources, setSources,
    types, setTypes,
    expandedId, setExpandedId,
    limit, setLimit,
    offset, setOffset,
    agePreset, setAgePreset,
    activeTab, setActiveTab,
    clearFilters,
  } = useOrgSearchParams(initialQuery);

  // Local input state (what the user is typing, before submission)
  const [inputValue, setInputValue] = useState(query);
  const [prevQuery, setPrevQuery] = useState(query);
  useEffect(() => {
    if (prevQuery !== query) {
      setPrevQuery(query);
      setInputValue(query);
    }
  }, [query, prevQuery]);

  // Build search request from URL-persisted params
  const searchInput = useMemo(
    () => ({
      query: query.trim(),
      limit,
      offset,
      mode,
      ...(sources.length > 0 && { sources }),
      ...(types.length > 0 && { types }),
      ...dateRangeFromPreset(agePreset),
    }),
    [query, limit, offset, mode, sources, types, agePreset]
  );

  // Search query — fires when URL params change and query is non-empty
  // queryKey includes clerkOrgId to prevent cross-org cache pollution
  const searchQuery = useQuery({
    queryKey: ["search", clerkOrgId, searchInput],
    queryFn: ({ signal }) => client.search(searchInput, { signal }),
    enabled: !!query.trim() && !!clerkOrgId,
    placeholderData: keepPreviousData,
  });

  const isSearching = searchQuery.isFetching;
  const searchResults = searchQuery.data ?? null;
  const error = searchQuery.error ? parseError(searchQuery.error) : null;

  // Submit handler — writes inputValue to URL, triggering the query
  const handlePromptSubmit = async (
    message: PromptInputMessage
  ): Promise<void> => {
    const content = message.text?.trim() ?? "";
    await setQuery(content);
  };

  const handleSearch = () => {
    void setQuery(inputValue);
  };

  // Handle Cmd+Enter keyboard shortcut
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if ((e.metaKey || e.ctrlKey) && e.key === "Enter" && !isSearching) {
      e.preventDefault();
      void handleSearch();
    }
  };

  return (
    // ... rest of JSX unchanged — uses isSearching, searchResults, error
    // exactly as before
  );
}
```

**Key behavioral changes**:
- `queryKey: ["search", clerkOrgId, searchInput]` — includes org ID to prevent cross-org cache hits when switching orgs with the same search query
- `queryFn: ({ signal }) => client.search(searchInput, { signal })` — signal forwarding is explicit; React Query passes its AbortSignal, the oRPC client forwards it through `OpenAPILink` to `fetch`
- `placeholderData: keepPreviousData` — keeps previous results visible while fetching new ones (matches current behavior: "Keep previous results visible during loading to avoid flash of empty state")
- Query auto-refetches when URL params change (filters, limit, offset) while a query is active. **This is a behavioral change**: currently filter changes require re-clicking search. With this approach, filter changes auto-trigger searches. This is intentional — it makes the UI more responsive.
- Error state resets automatically when a new query starts

**What stays the same**:
- `inputValue` / `prevQuery` local state pattern — user types freely, submission writes to URL
- `useOrgSearchParams` nuqs hook — all URL params preserved
- All JSX below the hooks — `SearchPromptInput`, `SearchFilters`, `SearchResultsPanel` receive the same props
- `OrgSearchSkeleton` export — unchanged

