### Changes Required:

#### 1. New File: `apps/app/src/lib/api-client.ts`

**Purpose**: Factory function that creates a session-authenticated oRPC client for calling `/v1/*` endpoints from the browser.

```ts
import { createORPCClient } from "@orpc/client";
import type { ContractRouterClient } from "@orpc/contract";
import type { JsonifiedClient } from "@orpc/openapi-client";
import { OpenAPILink } from "@orpc/openapi-client/fetch";
import { apiContract } from "@repo/app-api-contract";

export type ApiClient = JsonifiedClient<ContractRouterClient<typeof apiContract>>;

/**
 * Create a session-authenticated oRPC client for calling /v1/* endpoints
 * from the browser. Uses Clerk session cookies for auth and X-Org-ID header
 * for org scoping.
 */
export function createApiClient(clerkOrgId: string): ApiClient {
  const link = new OpenAPILink(apiContract, {
    url: "",
    headers: { "x-org-id": clerkOrgId },
    fetch: (request, init) => fetch(request, { ...init, credentials: "include" }),
  });

  return createORPCClient(link) as ApiClient;
}
```

**Design decisions**:
- `url: ""` — same-origin relative URL, requests go to `/v1/search` on the current host
- `credentials: "include"` — sends Clerk session cookies (same pattern as tRPC client at `packages/app-trpc/src/react.tsx:95`)
- `x-org-id` header — required by oRPC session auth path at `orpc-middleware.ts:67-72`
- `ContractRouterClient` and `JsonifiedClient` types from `@orpc/contract` and `@orpc/openapi-client` — follows the SDK pattern at `core/lightfast/src/index.ts:14-16`

**Critical: `fetch` callback signature** — `OpenAPILink`'s `fetch` receives `(request: Request, init)`, NOT `(url: string, init)`. The `AbortSignal` is baked into the `Request` object (`request.signal`), not passed via `init`. Using `(url, init)` would silently drop the signal. This was spike-validated.

**Note**: `@orpc/contract` must be installed as a direct dependency (Phase 1). It does NOT resolve as a transitive dep via `@repo/app-api-contract` in the pnpm workspace — also spike-validated.

